796	/// @brief Map provided qubit arguments to a vector of QuditInfo.
797	template <typename... QuantumT>
798	void qubitsToQuditInfos(const std::tuple<QuantumT...> &quantumTuple,
799	                        std::vector<QuditInfo> &qubits) {
800	  cudaq::tuple_for_each(quantumTuple, [&](auto &&element) {
801	    using T = decltype(element);
802	    if constexpr (IsQubitType<T>::value) {
803	      qubits.push_back(qubitToQuditInfo(element));
804	    } else if constexpr (IsQvectorType<T>::value || IsQviewType<T>::value ||
805	                         IsQarrayType<T>::value) {
806	      for (auto &q : element)
807	        qubits.push_back(qubitToQuditInfo(q));
808	    }
809	  });
810	}
811	
812	/// @brief Search through the qubit arguments and see which ones are negated.
813	template <typename... QuantumT>
814	void findQubitNegations(const std::tuple<QuantumT...> &quantumTuple,
815	                        std::vector<bool> &qubitIsNegated) {
816	  cudaq::tuple_for_each(quantumTuple, [&](auto &&element) {
817	    using T = decltype(element);
818	    if constexpr (IsQubitType<T>::value) {
819	      qubitIsNegated.push_back(element.is_negative());
820	    } else if constexpr (IsQvectorType<T>::value || IsQviewType<T>::value ||
821	                         IsQarrayType<T>::value) {
822	      for (auto &q : element)
823	        qubitIsNegated.push_back(q.is_negative());
824	    }
825	    return;
826	  });
827	}
