838	constexpr std::size_t count_qubits_compile_time() {
839	  if constexpr (detail::IsQubitType<T>::value) {
840	    return 1;
841	  } else if constexpr (detail::IsQarrayType<T>::value) {
842	    return std::tuple_size<std::decay_t<T>>::value;
843	  } else {
844	    return 0; // Dynamic containers handled at runtime
845	  }
846	}
