15	class state;
16	
17	/// The qudit models a general d-level quantum system.
18	/// This type is templated on the number of levels d.
19	template <std::size_t Levels>
20	class qudit {
21	  /// Every qudit has a logical index in the global qudit register,
22	  /// `idx` is this logical index, it must be
23	  /// provided at construction and is immutable.
24	  const std::size_t idx = 0;
25	
26	  // Bool to indicate if we are currently negated
27	  // as a control qudit.
28	  bool isNegativeControl = false;
29	
30	public:
31	  /// Construct a qudit, will allocated a new unique index
32	  qudit() : idx(getExecutionManager()->allocateQudit(n_levels())) {}
33	
34	  qudit(const state &state) : qudit() {
35	    // Note: the internal state data will be cloned by the simulator backend.
36	    std::vector<QuditInfo> v{QuditInfo{Levels, id()}};
37	    getExecutionManager()->initializeState(v, state.internal.get());
38	  }
39	  qudit(const state *s) : qudit(*s) {}
40	  qudit(state *s) : qudit(const_cast<const state *>(s)) {}
41	  qudit(state &s) : qudit(const_cast<const state &>(s)) {}
42	
43	  // Qudits cannot be copied
44	  qudit(const qudit &q) = delete;
45	  // qudits cannot be moved
46	  qudit(qudit &&) = delete;
47	
48	  // Return the unique id / index for this qudit
49	  std::size_t id() const { return idx; }
50	
51	  // Return this qudit's dimension
52	  static constexpr std::size_t n_levels() { return Levels; }
53	
54	  // Qudits used as controls can be negated, i.e
55	  // instead of applying a target op if the qudit is
56	  // in the vacuum state, you can apply a target op if the
57	  // state is in an excited state if this control qudit is negated
58	  qudit<Levels> &negate() {
59	    isNegativeControl = !isNegativeControl;
60	    return *this;
61	  }
62	
63	  // Is this qudit negated?
64	  bool is_negative() { return isNegativeControl; }
65	
66	  // Syntactic sugar for negating a control
67	  qudit<Levels> &operator!() { return negate(); }
68	
69	  // Destructor, return the qudit so it can be reused
70	  ~qudit() { getExecutionManager()->returnQudit({n_levels(), idx}); }
